"use client";
import { useRef, useState } from "react";
import { motion, useReducedMotion } from "framer-motion";
const chapters=[['Brief','Scope and constraints'],['Evidence','Signals behind the choice'],['Release','Next handoff date']];
export default function ChapterStampNav(){const [active,setActive]=useState(0);const refs=useRef<Array<HTMLButtonElement|null>>([]);const reduced=useReducedMotion();const pick=(index:number)=>{setActive(index);refs.current[index]?.focus();};const key=(event:React.KeyboardEvent<HTMLButtonElement>,index:number)=>{if(event.key==='ArrowRight')pick((index+1)%chapters.length);if(event.key==='ArrowLeft')pick((index+chapters.length-1)%chapters.length);if(event.key==='Home')pick(0);if(event.key==='End')pick(chapters.length-1);};return <section className="w-full max-w-sm rounded-[22px] border border-[#ececee] bg-white p-5 shadow-[0_10px_28px_rgba(17,17,17,.06)]"><p className="text-xs font-bold uppercase tracking-[.14em] text-[#4a4a4f]">project chapters</p><div role="tablist" aria-label="Project chapters" className="relative mt-4 flex gap-1 border-b border-[#ececee]"><motion.i aria-hidden animate={{x:active*98}} transition={reduced?{duration:.12}:{type:'spring',stiffness:360,damping:29}} className="absolute bottom-0 h-1 w-10 rounded-full bg-[#4f46e5]"/>{chapters.map((chapter,index)=><motion.button ref={element=>{refs.current[index]=element;}} key={chapter[0]} id={`chapter-${index}`} role="tab" aria-selected={active===index} aria-controls="chapter-panel" tabIndex={active===index?0:-1} onClick={()=>setActive(index)} onKeyDown={event=>key(event,index)} whileHover={reduced?undefined:{y:-2}} whileTap={reduced?undefined:{y:1}} className="min-h-11 flex-1 px-1 text-sm font-bold text-[#111] outline-offset-3 focus-visible:outline focus-visible:outline-[3px] focus-visible:outline-[#111]">{chapter[0]}</motion.button>)}</div><motion.p key={active} id="chapter-panel" role="tabpanel" aria-labelledby={`chapter-${active}`} initial={{opacity:0}} animate={{opacity:1}} className="mt-4 text-sm text-[#4a4a4f]">{chapters[active][1]}</motion.p></section>}
